INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57f41407-moex-00793', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '下列選項，成語使用正確的是：', '["董先生的演奏如「膠柱鼓瑟」般，令人沉醉", "小李行事為人，給人「白虹貫日」的氣象，令人佩服", "在秋高氣爽的時節，景色總是「瀟瀟颯颯」，令人愉悅", "顏教授博學多聞，研究領域「碧落黃泉」，令人敬佩"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00794', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '下列選項中，文句沒有語病的是：', '["他對自己的期待很高，努力進取，無時無刻在讀書", "五月的家鄉開滿了油桐花，是一年之中最美的季節", "經過三個月的努力，總算拿下這個案子，心裡很快樂", "儘管遇見多大的困難，我們也會堅持下去，使命必達"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00795', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '下列直式信封書寫方式說明，何者完全正確？', '["可分中、左、右三路，左路為受信人地址，右路為寄信人地址", "書寫受信人姓名時，為表尊重，字體經常略小且偏左側，稱為「諱側」", "受信人名字「諱側」時，為求美觀一致，其下先生或女士二字，亦應一併縮小", "啟封詞寫在受信人姓名稱呼之下，用語視受信人身分及其與自身關係加以選擇"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00796', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「秋色很深很深了吧？你撫娑著茫白而悲情的荻花，期待著即將告別燕土的彼刻。許會想起往昔，仍 是青衫少年的時刻以及情愛，書卷裡的歲月終究是無法力挽狂瀾的，倒不如以一把淬毒的精銅匕首。」 上文所描寫的人物，下列選項何者最適切？', '["豫讓", "荊軻", "聶隱娘", "紅拂女"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00797', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「月遺落遍地的影子，雲以纖手拾了去。」文中主要描寫的是：', '["一個萬里無雲的月夜", "地上的月影如同雲朵", "雲遮住了灑落的月光", "星光的輝耀勝過月色"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00798', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「以我觀之，流浪最大的好處是，丟開那些他平日認為最重要的東西。好比說，他的賺錢能耐，他的 社會占有度，他的侃侃而談（或訓話習慣），他的聰慧、迷人，或顧盼自雄，還有，他的自卑感。最不 願意流浪的人，或許是 ＿＿＿＿＿ 。」 依據文意，文中空缺處最適合填入的是：', '["最害怕孤獨的人", "最畏懼冒險的人", "最不願意放掉東西的人", "最不喜歡規劃行程的人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00799', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「烏龜對道路的了解遠勝於野兔。」關於這句話的涵義，下列敘述最正確的是：', '["慢慢來，其實會比較快", "路遙知馬力，日久見人心", "慢，可以是一種專注、覺察和體悟", "做自己擅長的事，可能會事半功倍"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00800', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「靜嘉堂坐落的住宅區，道路狹窄曲折，七彎八轉，才到達那座近似原始林一樣的公園。走上濃蔭夾 道的一條小路，再轉一個彎，才看到兩座飽經歲月的老房子。使我感到繁華的、處處標榜二十一世紀 的東京市，忽然在眼前消失了。其實這房子並不真老，只是在叢林之中的極靜，予人以時代的錯亂感 而已。」 根據上文，東京消失的主因，下列描述何者最接近？', '["建築周遭與都市常態不同", "小徑曲折外人不容易進入", "已經距離東京非常的遙遠", "作者心境平和已不受干擾"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00801', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '依據前後文意，選出排列最正確的選項： 「你從何時開始不愛照鏡、討厭照相，甲、仍掩不住那蒸蒸騰騰的香氛。 乙、即標示了你從那時開 始變老。 丙、所以，青春傾向張揚；愛攬鏡自照，愛攝影留戀， 丁、青春氣息是沛然莫之能禦的， 即使以炭塗面、衣衫襤褸， 愛不擇手段使那輝煌的美更美。」', '["乙甲丙丁", "乙丁甲丙", "丙甲丁乙", "丙丁甲乙"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00802', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「在與經典密切對話的過程中，讀者不斷地『生發』出對自己所關懷的問題具有新意義的東西來。 經典之所以歷久不衰，往往是提供了對話與創造的豐富資源。閱讀經典一方面是要『照著講』，同 時也要『接著講』。」 下列選項，最接近上文旨意的是：', '["經典不容質疑", "經典保存不易", "經典無可取代", "經典歷久彌新"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
